import os
import time

def retry(fn, max_attempts=3, delay=1.0):
    for i in range(max_attempts):
        try:
            return fn()
        except Exception:
            if i == max_attempts - 1:
                raise
            time.sleep(delay)

def ensure_dir(path):
    os.makedirs(path, exist_ok=True)
    return path

