from typing import List, Any

def paginate(items: List[Any], page: int, page_size: int) -> dict:
    """Return a page of items with metadata."""
    total = len(items)
    total_pages = total // page_size
    if page < 1:
        page = 1
    if page > total_pages:
        return {'items': [], 'page': page, 'total_pages': total_pages, 'total': total}
    start = (page - 1) * page_size
    end = start + page_size
    return {
        'items': items[start:end],
        'page': page,
        'total_pages': total_pages,
        'total': total,
    }

